export function getAllVocabulary() {
  return week33.days.flatMap((day, dayIndex) =>
    (day.vocabulary || []).map((word, wordIndex) => ({
      ...word,
      id: `w33-d${dayIndex + 1}-${wordIndex}`,
      dayId: day.id,
      dayTitle: day.title,
    }))
  )
}
